import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.concurrent.locks.*;

public class ConcurrencyMastery {
    // AtomicInteger for thread-safe counting without locks
    private static final AtomicInteger counter = new AtomicInteger(0);

    // ReentrantLock for fine-grained locking
    private static final ReentrantLock lock = new ReentrantLock();

    public static void main(String[] args) throws Exception {
        // ExecutorService with thread pool
        ExecutorService executor = Executors.newFixedThreadPool(4);

        for (int i = 0; i < 10; i++) {
            executor.submit(() -> {
                int current = counter.incrementAndGet();
                System.out.println(Thread.currentThread().getName() + " count: " + current);
            });
        }

        // Async composition
        CompletableFuture<Void> future = CompletableFuture
            .supplyAsync(() -> "Hello")
            .thenApply(s -> s + " World")
            .thenAccept(System.out::println);

        future.join(); // wait for completion

        executor.shutdown();
        executor.awaitTermination(5, TimeUnit.SECONDS);
    }
}

